      "chinese": "",
      "english": "Lately we've been reviewing our expenses more carefully to identify areas where we can optimize without sacrificing quality of life.",
      "sourceAudio": "中级/B6.mp3",
      "sourceDocument": "中级/B6.docx",
      "day": 6,
      "daySentence": 2,
