      "chinese": "",
      "english": "I try to celebrate their milestones as fully as I did when they were younger, just in different forms.",
      "sourceAudio": "中级/B13.mp3",
      "sourceDocument": "中级/B13.docx",
      "day": 13,
      "daySentence": 13,
      "id": 253
