      "chinese": "",
      "english": "You know, supporting their growth while honoring my own needs creates a healthier dynamic for everyone.",
      "sourceAudio": "中级/B13.mp3",
      "sourceDocument": "中级/B13.docx",
      "day": 13,
      "daySentence": 16,
      "id": 256
