const nativeFlowTranslationsByLevel =
  nativeFlowChineseTranslations as Partial<Record<NativeFlowLevelId, readonly string[]>>;

export function getNativeFlowLevel(levelId: string) {
  return nativeFlowLevels.find((level) => level.id === levelId);
}

function getNativeFlowSentenceAudioSrc(levelId: NativeFlowLevelId, sentence: NativeFlowSentence) {
  return `/native-flow-audio/${levelId}/day-${String(sentence.day).padStart(2, "0")}/sentence-${String(sentence.daySentence).padStart(2, "0")}.mp3`;
}

export function getNativeFlowSentence(levelId: string, sentenceId: number) {
  const level = getNativeFlowLevel(levelId);
  if (!level) return null;

  const normalizedSentenceId = Number.isFinite(sentenceId)
    ? Math.min(Math.max(Math.floor(sentenceId), 1), level.totalSentences)
    : 1;
  const sourceSentence = nativeFlowSentencesByLevel[level.id][normalizedSentenceId - 1];
  const translatedChinese =
    nativeFlowTranslationsByLevel[level.id]?.[normalizedSentenceId - 1] || "";
  const sentence =
    sourceSentence
      ? {
          ...sourceSentence,
          audioSrc: getNativeFlowSentenceAudioSrc(level.id, sourceSentence),
          chinese: sourceSentence.chinese || translatedChinese,
        }
      : sourceSentence;

  return sentence ? { level, sentence } : null;
}
